alter table public.business_chart_of_accounts drop constraint if exists business_chart_accounts_type_normal_check;

do $$begin if not exists(select 1 from pg_constraint where conrelid='public.business_chart_of_accounts'::regclass and conname='business_chart_accounts_type_normal_check') then alter table public.business_chart_of_accounts add constraint business_chart_accounts_type_normal_check check ((account_type='asset' and account_subtype='contra_asset' and normal_balance='credit') or (account_type='asset' and coalesce(account_subtype,'')<>'contra_asset' and normal_balance='debit') or (account_type='expense' and normal_balance='debit') or (account_type in ('liability','revenue') and normal_balance='credit') or (account_type='equity' and ((account_subtype='drawings' and normal_balance='debit') or (coalesce(account_subtype,'')<>'drawings' and normal_balance='credit')))); end if;end$$;

create table if not exists public.business_asset_settings (business_id uuid primary key references public.businesses(id) on delete cascade,default_depreciation_method text not null default 'straight_line',default_depreciation_convention text not null default 'full_month',gain_on_disposal_account_id uuid not null,loss_on_disposal_account_id uuid not null,updated_by uuid references auth.users(id) on delete set null,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),constraint business_asset_settings_method_check check (default_depreciation_method='straight_line'),constraint business_asset_settings_convention_check check (default_depreciation_convention in ('full_month','next_month')),constraint business_asset_settings_gain_fkey foreign key (business_id,gain_on_disposal_account_id) references public.business_chart_of_accounts(business_id,id) on delete restrict,constraint business_asset_settings_loss_fkey foreign key (business_id,loss_on_disposal_account_id) references public.business_chart_of_accounts(business_id,id) on delete restrict);

create table if not exists public.business_asset_categories (id uuid primary key default gen_random_uuid(),business_id uuid not null references public.businesses(id) on delete cascade,code text not null,name text not null,description text,asset_account_id uuid not null,accumulated_depreciation_account_id uuid not null,depreciation_expense_account_id uuid not null,default_useful_life_months integer not null default 60,default_residual_rate numeric(9,4) not null default 0,default_depreciation_method text not null default 'straight_line',default_depreciation_convention text not null default 'full_month',active boolean not null default true,created_by uuid references auth.users(id) on delete set null,updated_by uuid references auth.users(id) on delete set null,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),constraint business_asset_categories_business_id_id_key unique (business_id,id),constraint business_asset_categories_code_key unique (business_id,code),constraint business_asset_categories_code_check check (code ~ '^[A-Z0-9][A-Z0-9_-]{1,39}$'),constraint business_asset_categories_name_check check (char_length(btrim(name)) between 2 and 120),constraint business_asset_categories_description_check check (description is null or char_length(description)<=1000),constraint business_asset_categories_life_check check (default_useful_life_months between 1 and 1200),constraint business_asset_categories_residual_check check (default_residual_rate between 0 and 100),constraint business_asset_categories_method_check check (default_depreciation_method='straight_line'),constraint business_asset_categories_convention_check check (default_depreciation_convention in ('full_month','next_month')),constraint business_asset_categories_distinct_accounts_check check (asset_account_id<>accumulated_depreciation_account_id and asset_account_id<>depreciation_expense_account_id and accumulated_depreciation_account_id<>depreciation_expense_account_id),constraint business_asset_categories_asset_fkey foreign key (business_id,asset_account_id) references public.business_chart_of_accounts(business_id,id) on delete restrict,constraint business_asset_categories_accumulated_fkey foreign key (business_id,accumulated_depreciation_account_id) references public.business_chart_of_accounts(business_id,id) on delete restrict,constraint business_asset_categories_expense_fkey foreign key (business_id,depreciation_expense_account_id) references public.business_chart_of_accounts(business_id,id) on delete restrict);

create table if not exists public.business_fixed_assets (id uuid primary key default gen_random_uuid(),asset_no bigint generated always as identity unique,business_id uuid not null references public.businesses(id) on delete cascade,category_id uuid not null,branch_id uuid,asset_code text not null,name text not null,description text,serial_number text,location text,acquisition_date date not null,in_service_date date not null,original_cost numeric(24,4) not null,residual_value numeric(24,4) not null default 0,useful_life_months integer not null,depreciation_method text not null default 'straight_line',depreciation_convention text not null default 'full_month',status text not null default 'draft',capitalization_counter_account_id uuid,capitalization_journal_entry_id uuid,accumulated_depreciation numeric(24,4) not null default 0,book_value numeric(24,4) not null,last_depreciation_period_end date,disposal_date date,disposal_proceeds numeric(24,4),disposal_account_id uuid,disposal_journal_entry_id uuid,disposal_gain numeric(24,4),disposal_loss numeric(24,4),created_by uuid references auth.users(id) on delete set null,updated_by uuid references auth.users(id) on delete set null,activated_by uuid references auth.users(id) on delete set null,activated_at timestamptz,disposed_by uuid references auth.users(id) on delete set null,disposed_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),constraint business_fixed_assets_business_id_id_key unique (business_id,id),constraint business_fixed_assets_code_key unique (business_id,asset_code),constraint business_fixed_assets_category_fkey foreign key (business_id,category_id) references public.business_asset_categories(business_id,id) on delete restrict,constraint business_fixed_assets_branch_fkey foreign key (business_id,branch_id) references public.business_branches(business_id,id) on delete restrict,constraint business_fixed_assets_capitalization_account_fkey foreign key (business_id,capitalization_counter_account_id) references public.business_chart_of_accounts(business_id,id) on delete restrict,constraint business_fixed_assets_capitalization_journal_fkey foreign key (business_id,capitalization_journal_entry_id) references public.business_journal_entries(business_id,id) on delete restrict,constraint business_fixed_assets_disposal_account_fkey foreign key (business_id,disposal_account_id) references public.business_chart_of_accounts(business_id,id) on delete restrict,constraint business_fixed_assets_disposal_journal_fkey foreign key (business_id,disposal_journal_entry_id) references public.business_journal_entries(business_id,id) on delete restrict,constraint business_fixed_assets_code_check check (asset_code ~ '^[A-Z0-9][A-Z0-9_-]{1,39}$'),constraint business_fixed_assets_name_check check (char_length(btrim(name)) between 2 and 160),constraint business_fixed_assets_description_check check (description is null or char_length(description)<=2000),constraint business_fixed_assets_serial_check check (serial_number is null or char_length(btrim(serial_number))<=120),constraint business_fixed_assets_location_check check (location is null or char_length(btrim(location))<=160),constraint business_fixed_assets_dates_check check (in_service_date>=acquisition_date),constraint business_fixed_assets_cost_check check (original_cost>0 and residual_value>=0 and residual_value<original_cost and accumulated_depreciation>=0 and accumulated_depreciation<=original_cost-residual_value and book_value=original_cost-accumulated_depreciation),constraint business_fixed_assets_life_check check (useful_life_months between 1 and 1200),constraint business_fixed_assets_method_check check (depreciation_method='straight_line'),constraint business_fixed_assets_convention_check check (depreciation_convention in ('full_month','next_month')),constraint business_fixed_assets_status_check check (status in ('draft','active','fully_depreciated','disposed','written_off','cancelled')),constraint business_fixed_assets_disposal_values_check check (disposal_proceeds is null or disposal_proceeds>=0),constraint business_fixed_assets_state_check check ((status='draft' and capitalization_journal_entry_id is null and activated_at is null and disposal_journal_entry_id is null) or (status in ('active','fully_depreciated') and capitalization_journal_entry_id is not null and activated_at is not null and disposal_journal_entry_id is null and disposal_date is null) or (status in ('disposed','written_off') and capitalization_journal_entry_id is not null and disposal_journal_entry_id is not null and disposal_date is not null and disposed_at is not null) or (status='cancelled' and capitalization_journal_entry_id is null and disposal_journal_entry_id is null)));

create table if not exists public.business_asset_depreciation_runs (id uuid primary key default gen_random_uuid(),run_no bigint generated always as identity unique,business_id uuid not null references public.businesses(id) on delete cascade,branch_id uuid,period_start date not null,period_end date not null,posting_date date not null,status text not null default 'draft',asset_count integer not null default 0,total_depreciation numeric(24,4) not null default 0,journal_entry_id uuid,notes text,created_by uuid references auth.users(id) on delete set null,posted_by uuid references auth.users(id) on delete set null,posted_at timestamptz,cancelled_by uuid references auth.users(id) on delete set null,cancelled_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),constraint business_asset_depreciation_runs_business_id_id_key unique (business_id,id),constraint business_asset_depreciation_runs_branch_fkey foreign key (business_id,branch_id) references public.business_branches(business_id,id) on delete restrict,constraint business_asset_depreciation_runs_journal_fkey foreign key (business_id,journal_entry_id) references public.business_journal_entries(business_id,id) on delete restrict,constraint business_asset_depreciation_runs_month_check check (period_start=date_trunc('month',period_start)::date and period_end=(date_trunc('month',period_start)+interval '1 month - 1 day')::date and posting_date between period_start and period_end),constraint business_asset_depreciation_runs_status_check check (status in ('draft','posted','cancelled')),constraint business_asset_depreciation_runs_totals_check check (asset_count>=0 and total_depreciation>=0),constraint business_asset_depreciation_runs_notes_check check (notes is null or char_length(notes)<=2000),constraint business_asset_depreciation_runs_state_check check ((status='draft' and journal_entry_id is null and posted_at is null and cancelled_at is null) or (status='posted' and journal_entry_id is not null and posted_at is not null and cancelled_at is null) or (status='cancelled' and journal_entry_id is null and cancelled_at is not null)));

create unique index if not exists business_asset_depreciation_runs_open_period_idx on public.business_asset_depreciation_runs(business_id,coalesce(branch_id,'00000000-0000-0000-0000-000000000000'::uuid),period_start) where status in ('draft','posted');

create table if not exists public.business_asset_depreciation_lines (id uuid primary key default gen_random_uuid(),business_id uuid not null references public.businesses(id) on delete cascade,depreciation_run_id uuid not null,asset_id uuid not null,expense_account_id uuid not null,accumulated_depreciation_account_id uuid not null,opening_accumulated_depreciation numeric(24,4) not null,depreciation_amount numeric(24,4) not null,closing_accumulated_depreciation numeric(24,4) not null,closing_book_value numeric(24,4) not null,created_at timestamptz not null default now(),constraint business_asset_depreciation_lines_run_fkey foreign key (business_id,depreciation_run_id) references public.business_asset_depreciation_runs(business_id,id) on delete cascade,constraint business_asset_depreciation_lines_asset_fkey foreign key (business_id,asset_id) references public.business_fixed_assets(business_id,id) on delete restrict,constraint business_asset_depreciation_lines_expense_fkey foreign key (business_id,expense_account_id) references public.business_chart_of_accounts(business_id,id) on delete restrict,constraint business_asset_depreciation_lines_accumulated_fkey foreign key (business_id,accumulated_depreciation_account_id) references public.business_chart_of_accounts(business_id,id) on delete restrict,constraint business_asset_depreciation_lines_key unique (business_id,depreciation_run_id,asset_id),constraint business_asset_depreciation_lines_amounts_check check (opening_accumulated_depreciation>=0 and depreciation_amount>0 and closing_accumulated_depreciation=opening_accumulated_depreciation+depreciation_amount and closing_book_value>=0));

create table if not exists public.business_asset_audit_log (id bigint generated always as identity primary key,business_id uuid not null references public.businesses(id) on delete cascade,asset_id uuid,depreciation_run_id uuid,actor_user_id uuid references auth.users(id) on delete set null,action text not null,metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now(),constraint business_asset_audit_asset_fkey foreign key (business_id,asset_id) references public.business_fixed_assets(business_id,id) on delete cascade,constraint business_asset_audit_run_fkey foreign key (business_id,depreciation_run_id) references public.business_asset_depreciation_runs(business_id,id) on delete cascade,constraint business_asset_audit_action_check check (action ~ '^[a-z][a-z0-9_]{2,79}$'));

